import Nav from '@/components/Nav'; import { prisma } from '@/lib/db'; import { currentUser } from '@/lib/auth'; import { redirect, notFound } from 'next/navigation';
async function enroll(formData:FormData){ 'use server'; const user=await currentUser(); if(!user) redirect('/login'); const courseId=String(formData.get('courseId')); await prisma.enrollment.upsert({where:{userId_courseId:{userId:user.id,courseId}},update:{},create:{userId:user.id,courseId}}); redirect(`/learn/${courseId}`); }
export default async function Detail({params}:{params:Promise<{slug:string}>}){ const {slug}=await params; const course=await prisma.course.findUnique({where:{slug},include:{category:true,lecturer:true,sections:{include:{lessons:true},orderBy:{position:'asc'}}}}); if(!course) notFound(); return <><Nav/><main className="mx-auto max-w-6xl px-5 py-10"><div className="grid gap-8 lg:grid-cols-[1.3fr_.7fr]"><section><p className="font-bold text-brand-600">{course.category.name} • {course.level}</p><h1 className="mt-3 text-5xl font-black">{course.title}</h1><p className="mt-5 text-xl text-slate-600">{course.description}</p><h2 className="mt-10 text-2xl font-black">Learning outcomes</h2><ul className="mt-3 list-disc pl-6 text-slate-700">{course.outcomes.split('\n').map((o,i)=><li key={i}>{o}</li>)}</ul><h2 className="mt-10 text-2xl font-black">Course content</h2><div className="mt-4 space-y-3">{course.sections.map(s=><div key={s.id} className="card p-4"><h3 className="font-black">{s.title}</h3><p className="text-sm text-slate-500">{s.lessons.length} lessons</p></div>)}</div></section><aside className="card h-fit p-6"><div className="rounded-2xl bg-gradient-to-br from-brand-600 to-slate-900 p-10 text-white">Course preview</div><p className="mt-5 text-3xl font-black">{course.priceCents?'Paid':'Free'}</p><form action={enroll}><input type="hidden" name="courseId" value={course.id}/><button className="btn mt-4 w-full">Enrol now</button></form><p className="mt-4 text-sm text-slate-500">Includes lesson notes, resources, discussion, and AI chatbot.</p></aside></div></main></> }
